import React from 'react';
import { MainLayout } from '../layouts';

const ContactPage = () => {
  return (
    <MainLayout>
      <div className="contact-page">
        <h1>Liên hệ</h1>
        <p>Thông tin liên hệ với chúng tôi</p>
      </div>
    </MainLayout>
  );
};

export default ContactPage;
